/**
 * Tool state for real-time UI updates
 */
export interface ToolState {
  id: string;
  type: ToolType;
  status: 'initializing' | 'building' | 'completed' | 'error';
  progress: number; // 0-1
  content: unknown;
  error?: string;
  createdAt: Date;
}

/**
 * Context passed to tool handlers
 */
export interface ToolContext {
  sessionId?: string;
  userId?: string;
  maestroId?: string;
  conversationId?: string;
